mapper.select:
SELECT I.ISSUE_ID, I.PROJECT_ID, P.PROJECT_CODE, P.PROJECT_NAME, I.ISSUE_KEY, I.TITLE, I.ISSUE_TYPE, I.STATUS, I.PRIORITY, I.ASSIGNEE_ID, COALESCE(U.DISPLAY_NAME, U.USERNAME) AS ASSIGNEE_NAME, I.DUE_DATE, I.ESTIMATED_MINUTES, I.SPENT_MINUTES FROM ISSUE I INNER JOIN PROJECT P ON I.PROJECT_ID = P.PROJECT_ID LEFT JOIN APP_USER U ON I.ASSIGNEE_ID = U.USER_ID
AND I.STATUS IN ('REGISTERED', 'ANALYZING', 'IN_PROGRESS', 'DEV_DONE', 'TESTING', 'DONE')
AND I.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND I.ASSIGNEE_ID = #{assigneeId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND I.PRIORITY = #{priority}
AND ( I.ISSUE_KEY ILIKE CONCAT('%', #{keyword}, '%') OR I.TITLE ILIKE CONCAT('%', #{keyword}, '%') OR P.PROJECT_CODE ILIKE CONCAT('%', #{keyword}, '%') OR P.PROJECT_NAME ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY CASE I.STATUS WHEN 'REGISTERED' THEN 1 WHEN 'ANALYZING' THEN 2 WHEN 'IN_PROGRESS' THEN 3 WHEN 'DEV_DONE' THEN 4 WHEN 'TESTING' THEN 5 WHEN 'DONE' THEN 6 ELSE 9 END, CASE I.PRIORITY WHEN 'URGENT' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'NORMAL' THEN 3 WHEN 'LOW' THEN 4 ELSE 9 END, CASE WHEN I.DUE_DATE IS NULL THEN 1 ELSE 0 END, I.DUE_DATE ASC, I.CREATED_AT DESC

SELECT DISTINCT U.USER_ID AS ASSIGNEE_ID, COALESCE(U.DISPLAY_NAME, U.USERNAME) AS ASSIGNEE_NAME FROM ISSUE I INNER JOIN APP_USER U ON I.ASSIGNEE_ID = U.USER_ID
AND I.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
ORDER BY ASSIGNEE_NAME ASC
